<?php
namespace Database\Seeders;
use App\Models\Gallery;use App\Models\GalleryImage;use App\Models\GuildUnion;use App\Models\PostCategory;use App\Models\User;use Illuminate\Database\Seeder;
class GallerySeeder extends Seeder{public function run():void{$admin=User::first();$cat=PostCategory::first();$unions=GuildUnion::all()->values();$titles=['گزارش تصویری نشست اتحادیه‌ها','بازدید از بازار گرگان','آیین تقدیر از پیشکسوتان اصناف','دوره آموزشی واحدهای صنفی','جلسه کمیسیون نظارت','نمایشگاه توانمندی‌های اصناف'];foreach($titles as $i=>$title){$gallery=Gallery::updateOrCreate(['slug'=>'gallery-'.($i+1)],['title'=>$title,'description'=>'گالری نمونه برای تست نمایش تصاویر و لایت‌باکس قالب اصلی.','cover_image'=>'assets/img/asnaf-gorgan-default.jpg','category_id'=>$cat?->id,'union_id'=>$unions->isNotEmpty()?$unions[$i%$unions->count()]->id:null,'status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);for($j=1;$j<=4;$j++){GalleryImage::updateOrCreate(['gallery_id'=>$gallery->id,'sort_order'=>$j],['image'=>'assets/img/asnaf-gorgan-default.jpg','caption'=>'تصویر '.$j.' '.$title]);}}}}
